input.new_string:
export function processScenario(scenario: Scenario): unknown[] {
  const results: unknown[] = [];

  for (const step of scenario.steps) {
    if (step.type === "quote") {
      const items = step.items!;
      const basePremium = calculateBasePremium(items);
      const itemSurcharges = calculateItemSurcharges(items);
      const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
      const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
      const followUpDiscount = calculateFollowUpDiscount(scenario.customer, basePremium);
      const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
      results.push({ premium });
    } else if (step.type === "claim") {
      const policyStep = scenario.steps[step.policy!];
      const policyItems = policyStep.items!;
      const insuranceSum = policyItems.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
      const cap = insuranceSum * 2;
      const totalPayout = step.damages!.reduce((sum, damage) => sum + Math.max(damage.amount - DEDUCTIBLE, 0), 0);
      const payout = Math.min(totalPayout, cap);
      const remainingCap = cap - payout;
      results.push({ payout, remainingCap });
    }
  }

  return results;
}

