7	interface Damage {
8	  type: string;
9	  amount: number;
10	}
11	
12	interface Step {
13	  type: string;
14	  items?: Item[];
15	  policy?: number;
16	  damages?: Damage[];
17	}
18	
19	interface Customer {
20	  yearsWithMHPCO: number;
21	  quoteNumber?: number;
22	}
23	
24	interface Scenario {
25	  customer: Customer;
26	  steps: Step[];
27	}
28	
29	const PROCESSING_FEE = 5;
30	const FIRST_INSURANCE_RATE = 0.1;
31	
32	const BASE_PREMIUM: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	const BLOCK_SIZE = 3;
43	const BLOCK_PREMIUM = 60;
44	const CURSE_SURCHARGE_RATE = 0.5;
45	const HIGH_ENCHANTMENT_THRESHOLD = 5;
46	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
47	const LOYALTY_THRESHOLD_YEARS = 2;
48	const LOYALTY_DISCOUNT_RATE = 0.2;
49	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
50	const DEDUCTIBLE = 100;
51	
52	const INSURANCE_VALUE: Record<string, number> = {
53	  sword: 1000,
54	};
55	
56	function calculateBasePremium(items: Item[]): number {
57	  const typeCounts: Record<string, number> = {};
58	  for (const item of items) {
59	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
60	  }
61	
62	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
63	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
64	      ? BLOCK_PREMIUM
65	      : count * BASE_PREMIUM[type];
66	    return total + premium;
67	  }, 0);
68	}
69	
70	function calculateLoyaltyDiscount(customer: Customer, basePremium: number): number {
71	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
72	    ? basePremium * LOYALTY_DISCOUNT_RATE
73	    : 0;
74	}
75	
76	function calculateFollowUpDiscount(customer: Customer, basePremium: number): number {
77	  return (customer.quoteNumber ?? 1) >= 2
78	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
79	    : 0;
80	}
81	
82	function calculateItemSurcharges(items: Item[]): number {
83	  return items.reduce((total, item) => {
84	    const itemBasePremium = BASE_PREMIUM[item.type];
85	    const curseSurcharge = item.cursed ? itemBasePremium * CURSE_SURCHARGE_RATE : 0;
86	    const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
87	      ? itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
88	      : 0;
89	    return total + curseSurcharge + enchantmentSurcharge;
90	  }, 0);
91	}
92	
93	export function processScenario(scenario: Scenario): unknown[] {
94	  const results: unknown[] = [];
95	
96	  for (const step of scenario.steps) {
97	    if (step.type === "quote") {
98	      const items = step.items!;
99	      const basePremium = calculateBasePremium(items);
100	      const itemSurcharges = calculateItemSurcharges(items);
101	      const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
102	      const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
103	      const followUpDiscount = calculateFollowUpDiscount(scenario.customer, basePremium);
104	      const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
105	      results.push({ premium });
106	    } else if (step.type === "claim") {
107	      const policyStep = scenario.steps[step.policy!];
108	      const policyItems = policyStep.items!;
109	      const insuranceSum = policyItems.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
110	      const cap = insuranceSum * 2;
111	      const totalPayout = step.damages!.reduce((sum, damage) => sum + Math.max(damage.amount - DEDUCTIBLE, 0), 0);
112	      const payout = Math.min(totalPayout, cap);
113	      const remainingCap = cap - payout;
114	      results.push({ payout, remainingCap });
115	    }
116	  }
117	
118	  return results;
119	}
